Data Cleaning

schedule_intervals &lt;- schedule |&gt; 
  mutate(length = end_datetime_local - start_datetime_local)


events &lt;- schedule |&gt; 
  select(-date, -day_of_week) |&gt; 
  distinct(.keep_all = TRUE)

time_grid &lt;- tibble(
  time = seq(
    from = floor_date(min(events$start_datetime_local), "hour"),
    to   = ceiling_date(max(events$end_datetime_local), "hour"),
    by   = "60 min"
  )
)

density &lt;- events |&gt;
  mutate(key = 1) |&gt;
  inner_join(time_grid |&gt; mutate(key = 1), by = "key", relationship = "many-to-many") |&gt;
  filter(start_datetime_local &lt;= time, end_datetime_local &gt; time) |&gt;
  count(time, discipline_name, name = "n_events") |&gt; 
  mutate(total = sum(n_events), .by = discipline_name) |&gt; 
  mutate(discipline_name = fct_reorder(discipline_name, total))

sidex &lt;- density |&gt; 
  summarise(total_events = sum(n_events), .by = time)

sidey &lt;- events |&gt; 
  summarise(total_events = n(), .by = discipline_name)

Data Cleaning

animals &lt;- dataset |&gt; 
  filter(measure %in% c("Total Sheep",
                        "Total Cattle",
                        "Number of alpacas",
                        "Total goats",
                        "Total Pigs",
                        "Total Deer"
                        )) |&gt; 

  left_join(nz_pop, by = c("year_ended_june" = "year")) |&gt; 
  drop_na(population) |&gt; 
  mutate(animal_people = value / population) |&gt; 
  mutate(value_label = str_remove(value_label, "Number of"),
         value_label = str_to_title(value_label))

Data Cleaning

lorenz_df &lt;- companies |&gt; 
  filter(!is.na(capital_stock),
         capital_stock &gt; 0,
         !is.na(owner_qualification)) |&gt; 
  group_by(owner_qualification) |&gt; 
  ungroup() |&gt; 

  group_by(owner_qualification) |&gt; 
  arrange(capital_stock, .by_group = TRUE) |&gt; 
  mutate(
    firm_rank   = row_number(),
    firm_share  = firm_rank / n(),
    capital_cum = cumsum(capital_stock),
    capital_share = capital_cum / sum(capital_stock)
  ) |&gt; 
  ungroup()

owner_order &lt;- lorenz_df %&gt;%
  group_by(owner_qualification) %&gt;%
  summarise(
    capital_top_1pct = capital_share[which.min(abs(firm_share - 0.99))]
  ) %&gt;%
  arrange(capital_top_1pct) %&gt;%
  pull(owner_qualification)

lorenz_df &lt;- lorenz_df %&gt;%
  mutate(
    owner_qualification = factor(owner_qualification,
                                 levels = owner_order)
  )

Data Cleaning

sun_mentions &lt;- apod |&gt; 
mutate(
  sun_mention =
    str_detect(title, regex("(?&lt;![A-Za-z])sun(?![A-Za-z])", ignore_case = TRUE)) |
    str_detect(explanation, regex("(?&lt;![A-Za-z])sun(?![A-Za-z])", ignore_case = TRUE)))

sun_mentions_cleaned &lt;- sun_mentions |&gt; 
  filter(sun_mention == TRUE)

# Compute % of month with sun mentioned
apod_solar &lt;- sun_mentions |&gt;
  mutate(
    month = month(date, label = TRUE, abbr = TRUE),
    year = year(date)) |&gt;
  group_by(year, month) |&gt;
  summarise(
    sun_share = mean(sun_mention, na.rm = TRUE),
    .groups = "drop")

apod_solar_side_x &lt;- sun_mentions |&gt;
  mutate(
    month = month(date, label = TRUE, abbr = TRUE),
    year = year(date)) |&gt;
  group_by(year) |&gt;
  summarise(
    sun_share = sum(sun_mention, na.rm = TRUE),
    .groups = "drop")

apod_solar_side_y &lt;- sun_mentions |&gt;
  mutate(
    month = month(date, label = TRUE, abbr = TRUE),
    year = year(date)) |&gt;
  group_by(month) |&gt;
  summarise(
    sun_share = sum(sun_mention, na.rm = TRUE),
    .groups = "drop")

Data Cleaning

text &lt;- christmas_novel_text |&gt; select(2) |&gt; 
  unnest_tokens(word, text)

word_cleaned &lt;- text |&gt; 
  drop_na() |&gt; 
  anti_join(stop_words, by = "word") |&gt; 
  filter(!word %in% stopwords("en")) |&gt; 
  filter(!word %in% stopwords("de")) 

wordcount &lt;- word_cleaned |&gt; 
  count(word, sort = TRUE)

Top 10 Most Powerful Passports

t &lt;- world |&gt; 
  st_drop_geometry() |&gt; 
  filter(!year %in% c("2007", "2009")) |&gt;
  select(iso_a2, country, visa_free_count, year) |&gt; 
  arrange(year, .by = country) |&gt; 
  reframe(visa_free_count_list = list(visa_free_count),
          .by = country) |&gt; 
  drop_na(country)

world |&gt; 
  st_drop_geometry() |&gt; 
  filter(year %in% c("2025", "2024")) |&gt;
  select(iso_a2, country, visa_free_count, year) |&gt; 
  pivot_wider(names_from = year, values_from = visa_free_count) |&gt; 
  relocate(`2025`, .before = `2024`) |&gt; 
  mutate(change = `2025` - `2024`) |&gt; 
  left_join(t, by = "country") |&gt; 
  arrange(desc(`2025`)) |&gt; 
  head(10) |&gt; 
  gt() |&gt; 
  fmt_flag(columns = iso_a2) |&gt; 
  cols_add(dir = ifelse(`2024` &lt; `2025`, "arrow-up", "arrow-down")) |&gt; 
  fmt_icon(
    columns = dir,
    fill_color = c("arrow-up" = "green", "arrow-down" = "red")
  ) |&gt; 
  cols_hide(c(`2025`, `2024`)) |&gt;
  cols_move(dir, after = change) |&gt; 
  gt_plt_sparkline(column = visa_free_count_list,
                   fig_dim = c(20, 30)) |&gt; 
  cols_label(iso_a2 = "",
             dir = "",
             country = "Country",
             change = "2024-2025 Change",
             visa_free_count_list = "Visa Free Count \nOver Time (2006-2025)") |&gt; 
  cols_align(columns = 5, align = "center") |&gt; 
  tab_header(
    title = md("**Top 10 Most Powerful Passports**")
  ) |&gt; 
  opt_table_font(font = "Courier New") |&gt; 
    tab_options(
    table.background.color = "white"
  )














